const ids = Array.from({ length: 200 }, (_, i) => i + 1);
flow.set('slaveIds', ids, 'file');
flow.set('onlineIds', [], 'file');
flow.set('activeSlaveIds', [], 'file');
flow.set('rrIndex', 0, 'file');

let settings = flow.get('deviceSettings', 'file') || {};
let tableData = flow.get('tableData', 'file') || {};

if (Object.keys(tableData).length === 0) {
