if (msg.payload.action === 'device-settings-save') {
    let d = msg.payload;
    let settings = flow.get('deviceSettings', 'file') || {};
    settings['slave_' + d.id] = { Location: d.location || '', RoomNo: d.roomNo || '', LSP: parseFloat(d.lsp) || 0, HSP: parseFloat(d.hsp) || 0 };
    flow.set('deviceSettings', settings, 'file');
